const items = $input.all();
const config = $('Por cada marca').item.json;
const fieldMap = config.field_map || {};

// Parsear CSV o transformar respuesta API al formato estándar
const rawProducts = Array.isArray(items[0].json) ? items[0].json : [items[0].json];

const normalized = rawProducts.map(p => ({
  brand_id: config.brand_id,
  external_id: String(p.id || p.sku || p[fieldMap.external_id] || ''),
  name: p.name || p.title || p[fieldMap.name] || 'Producto sin nombre',
  description: p.description || p.body_html || p[fieldMap.description] || null,
  category: p.category || p.type || p[fieldMap.category] || null,
  image_url_original: p.image?.src || p.images?.[0]?.src || p[fieldMap.image] || null,
  price: p.price ? parseInt(p.price) : null,
})).filter(p => p.image_url_original);

return normalized.map(p => ({ json: p }));

const item = $input.item.json;
const brandId = item.brand_id;
const externalId = item.external_id;

return [{
  json: {
    ...item,
    image_url: `{{ $env.MINIO_URL }}/images/enterprise/${brandId}/${externalId}.png`
  }
}];
